/* Joint optimization of build + paired cached correlate at one shared FFT size.
 * Constants derived from measure_phase_split() — re-run on this hardware.
 * PAIRED_CACHED_CORR_RATIO: cost of paired cached correlate relative to one full
 *   FFT pipeline. Measured as fwd + 2×(pw+ifft) relative to 2×fwd+pw+ifft.
 *   On M3 Max: (0.30 + 2×0.365) / 1.0 = 1.03.
 * FMA_NS: nanoseconds per scalar FMA. Schoolbook and correction loops use this.
 *   On M3 Max (NEON, 2-wide): 0.25. On Zen 4 (AVX-512, 8-wide): measure. */
/* K_CROSS: linear→hybrid crossover. Measured via ./bench_grid crossover. */
#ifndef K_CROSS_BATCHED
#define K_CROSS_BATCHED 150  /* for n >= 2048 (batched linear with BQ=8 AVX-512) */
#endif
#ifndef K_CROSS_PLAIN
#define K_CROSS_PLAIN 95     /* for n < 2048 (non-batched linear) */
#endif

/* L2_CACHE_SIZE: per-core L2 in bytes. Zen 4 has 1MB/core.
 * Used for batched linear checkpointing — segment must fit in L2. */
#ifndef L2_CACHE_SIZE
#define L2_CACHE_SIZE 1048576  /* 1MB */
#endif

#ifndef PAIRED_CACHED_CORR_RATIO
#define PAIRED_CACHED_CORR_RATIO 1.08
#endif
#ifndef FMA_NS
#define FMA_NS 0.13
#endif
#ifndef FFT_OVERHEAD_NS
#define FFT_OVERHEAD_NS 21.0
#endif
#ifndef INDEP_PAIR_RATIO
#define INDEP_PAIR_RATIO 1.35
#endif
#ifndef POLYMUL_FMA_NS
#define POLYMUL_FMA_NS 0.135
#endif

static double best_fft_config_joint(int build_conv, int corr_conv, int p_eff,
                                     int *out_size, int *out_build_m, int *out_corr_m) {
    int max_conv = (build_conv > corr_conv) ? build_conv : corr_conv;
    int min_size = max_conv / 2 + 1;

    int lo = 0, hi = N_CALIBRATED_SIZES - 1;
    int half = min_size;
    while (lo < hi) { int mid = (lo+hi)>>1; if (calib_sizes[mid] < half) lo = mid+1; else hi = mid; }

    double best_cost = 1e18;
    *out_size = 0; *out_build_m = 0; *out_corr_m = 0;

    for (int i = lo; i < N_CALIBRATED_SIZES; i++) {
        int S = calib_sizes[i];
        if (S > 2 * max_conv) break;
        if (S < min_size) continue;
        int mb = (S >= build_conv) ? 0 : build_conv - S;
        int mc = (S >= corr_conv) ? 0 : corr_conv - S;
        int corr_input_wrap = mc * p_eff;
        double cost = calib_times_ns[i]
                    + (double)(mb+1)*(mb+1) * FMA_NS
                    + calib_times_ns[i] * PAIRED_CACHED_CORR_RATIO
                    + 2.0 * ((double)(mc+1)*(mc+1) + corr_input_wrap) * FMA_NS;
        if (cost < best_cost) {
            best_cost = cost;
            *out_size = S;
            *out_build_m = mb;
            *out_corr_m = mc;
        }
    }
    return best_cost;
}

static void best_fft_config(int L, int *out_size, int *out_wrap_m, int len_P) {
    int lo = 0, hi = N_CALIBRATED_SIZES - 1;
    int half_L = L > 1 ? L / 2 : 1;
    while (lo < hi) { int mid = (lo+hi)>>1; if (calib_sizes[mid] < half_L) lo = mid+1; else hi = mid; }

    double best_cost = 1e18;
    *out_size = 0; *out_wrap_m = 0;

    int min_size = L / 2 + 1;
    for (int i = lo; i < N_CALIBRATED_SIZES; i++) {
        int S = calib_sizes[i];
        if (S > 2 * L) break;
        if (S < min_size) continue;
        int m = (S >= L) ? 0 : L - S;
        /* Correction: output-wrap (m+1)² + input-wrap m × len_P.
         * Input-wrap only applies to cross-correlation (correlate), not convolution
         * (polymul). Callers pass len_P=0 for polymul to skip input-wrap cost. */
        double correction = ((double)(m+1) * (m+1) + (double)m * len_P) * FMA_NS;
        double cost = calib_times_ns[i] + correction;
        if (cost < best_cost) {
            best_cost = cost;
            *out_size = S;
            *out_wrap_m = m;
        }
    }
}
